use crate::{
    packets::{
        packet::MAX_PACKET_SIZE,
        packetpayload::DeserializableBorrowed,
        tx::{TxBorrowed, TxRef},
    },
    util::arena::Arena,
};

use super::size::calculate_tx_size_wus;

#[test]
fn test_size() {
    let allocator = Arena::new(MAX_PACKET_SIZE);
    // Non-witness tx 1
    // Transaction 791bd9b3bda632ee1757de37db8939b0287ece4753f3077b9a5f5c7e28545967
    let encoded_tx1 = hex::decode("").unwrap();
    let tx1 = allocator.try_alloc_default::<TxBorrowed>().unwrap();
    tx1.deserialize_borrowed(&allocator, &encoded_tx1).unwrap();
    let size1 = calculate_tx_size_wus(TxRef::Borrowed(tx1));
    assert_eq!(size1, 900);

    // Non-witness tx 2
    // Transaction e3d0425ab346dd5b76f44c222a4bb5d16640a4247050ef82462ab17e229c83b4
    let encoded_tx2 = hex::decode("").unwrap();
    let tx2 = allocator.try_alloc_default::<TxBorrowed>().unwrap();
    tx2.deserialize_borrowed(&allocator, &encoded_tx2).unwrap();
    let size2 = calculate_tx_size_wus(TxRef::Borrowed(tx2));
    assert_eq!(size2, 1032);

    // Witness tx 1
    // Transaction 3d0acedc2f5787d2fbefa85e72ef6aac0465e78e4d3f05ae5f813488420bde38
    let encoded_tx3 = hex::decode("").unwrap();
    let tx3 = allocator.try_alloc_default::<TxBorrowed>().unwrap();
    tx3.deserialize_borrowed(&allocator, &encoded_tx3).unwrap();
    let size3 = calculate_tx_size_wus(TxRef::Borrowed(tx3));
    assert_eq!(size3, 565);

    // Witness tx 2
    // Transaction 0cca3800ae72754717e21f5105f25a28cb65783d3ad26f6669d7798c8b283938
    let encoded_tx4 = hex::decode(
        "",
    ).unwrap();
    let tx4 = allocator.try_alloc_default::<TxBorrowed>().unwrap();
    tx4.deserialize_borrowed(&allocator, &encoded_tx4).unwrap();
    let size4 = calculate_tx_size_wus(TxRef::Borrowed(tx4));
    assert_eq!(size4, 110796);
}
